const input = $input.first().json;
const bodyData = input.body || {};
const { nombre, tipo, nivel, categoria, dia_1, dia_2, hora_inicio, hora_fin, cupo_max, precio_mensual, descripcion } = bodyData;

if (!nombre || !tipo || !nivel || !categoria || !dia_1 || !dia_2 || !hora_inicio || !hora_fin || !cupo_max) {
  throw new Error(`Faltan campos requeridos. Recibido: ${JSON.stringify(bodyData)}`);
}

const query = `INSERT INTO horarios (nombre, tipo, nivel, categoria, dia_1, dia_2, hora_inicio, hora_fin, cupo_max, cupo_actual, precio_mensual, descripcion, activo)
VALUES ('${nombre.replace(/'/g, "''")}', '${tipo}', '${nivel}', '${categoria}', '${dia_1}', '${dia_2}', '${hora_inicio}'::time, '${hora_fin}'::time, ${parseInt(cupo_max)}, 0, ${precio_mensual ? parseFloat(precio_mensual) : 'null'}, ${descripcion ? `'${descripcion.replace(/'/g, "''")}'` : 'null'}, TRUE)
RETURNING id, nombre, tipo, nivel, categoria, dia_1, dia_2, hora_inicio, hora_fin, cupo_max, activo;`;

return [{
  json: {
    query
  }
}];

const horario = $('arma query').first().json;

return [{
  json: {
    success: true,
    mensaje: 'Horario creado correctamente',
    horario
  }
}];

